 * @return an XML declaration if it could be parsed as one, null otherwise.
 */
public XmlDeclaration asXmlDeclaration() {
    String data = getData();
    // Need at least 2 characters for a valid XML declaration (e.g. "?x?" or "!x>")
    if (data.length() < 2) {
        return null;
    }

    // Check if the first character is ? or ! (as per isXmlDeclaration method)
    char firstChar = data.charAt(0);
    if (firstChar != '?' && firstChar != '!') {
        return null;
    }

    String content;
    // For properly formatted XML/DTP declarations, extract the content between markers
    try {
        if (firstChar == '?' && data.charAt(data.length() - 1) == '?') {
            // XML declaration like <?xml?>
            if (data.length() == 2) {
                // Just "??", no content
                return null;
            }
            content = data.substring(1, data.length() - 1);
        } else if (firstChar == '!' && data.charAt(data.length() - 1) == '>') {
